    const backdatedEntries = records.cashBookEntries.map(row => ({ ...row, businessDate: '2026-07-17', occurredAt: '2026-07-17T10:00:00.000Z', createdAt: '2026-07-17T10:01:00.000Z' }))
    const backdatedSource = { ...validSource, cashBookEntries: backdatedEntries }
    await expect(createAuditPackage(backdatedSource, { ...access, purpose: 'MIGRATION' }, { record: vi.fn() }, migrationAuthenticator)).rejects.toThrow('after the final close')
    const tampered = resignFile(pkg, 'data/cashBookEntries.json', canonicalJson(backdatedEntries))
    expect(verifyAuditPackage(tampered).join('; ')).toContain('after the final close')
    expect(() => importMigrationPackage(tampered, tenant, migrationAuthenticator)).toThrow('after the final close')
    expect(() => reconstructCashBooks(backdatedSource)).toThrow('after the final close')
