function resignFile(pkg: AuditPackage, path: string, contents: string): AuditPackage { const files = { ...pkg.files, [path]: contents }; const parsed = JSON.parse(contents); const manifestFiles = pkg.manifest.files.map(file => file.path === path ? { ...file, bytes: Buffer.byteLength(contents), sha256: createHash('sha256').update(contents).digest('hex'), rows: Array.isArray(parsed) ? parsed.length : 0 } : file); const { packageChecksum: _old, ...base } = { ...pkg.manifest, files: manifestFiles }; const manifest = { ...base, files: manifestFiles, packageChecksum: createHash('sha256').update(canonicalJson(base)).digest('hex') }; return { files, manifest, authenticity: { keyId: migrationAuthenticator.keyId, signature: migrationAuthenticator.sign(migrationSignaturePayload(manifest)) } } }

function procedure(version = '1.0.0', from = '2025-01-01', to?: string): ProcedureDocumentVersion { return { id: 'vd-1', version, effectiveFrom: from, effectiveTo: to, approvedBy: 'Management', approvedAt: `${from}T09:00:00Z`, appVersion: '0.1.0', configurationVersion: 'cfg-2', schemaVersion: '20260717', taxonomyVersions: ['6.9'], sections: Object.fromEntries(['general', 'user', 'technical', 'operations', 'capture', 'posting', 'correction', 'closing', 'archiving', 'reporting', 'interfaces', 'access', 'backup-recovery'].map(key => [key, `${key} process`])) as ProcedureDocumentVersion['sections'], controls: Object.fromEntries(['roles-approvals', 'separation-of-duties', 'completeness', 'reconciliation', 'exception-handling', 'control-evidence'].map(key => [key, { description: key, ownerRole: 'Controller', evidenceReferences: [`EV-${key}`] }])) as ProcedureDocumentVersion['controls'], changeLog: [{ changedAt: from, changedBy: 'Admin', summary: `Release ${version}` }] } }
const operator: TenantProcedureDetails = { tenantId: tenant, legalName: 'Beispiel GmbH', operatorRoles: { poster: 'Alice', approver: 'Bob' }, procedures: { capture: 'Scan queue', posting: 'Four-eyes', closing: 'Checklist', 'backup-recovery': 'Daily encrypted backup, quarterly restore test' }, evidenceIndex: ['EV-roles-approvals', 'EV-separation-of-duties', 'EV-completeness', 'EV-reconciliation', 'EV-exception-handling', 'EV-control-evidence'] }
const operatorSnapshots: TenantProcedureSnapshot[] = [{ id: 'operator-2025', effectiveFrom: '2025-01-01', effectiveTo: '2025-12-31', details: { ...operator, operatorRoles: { poster: 'Historic Alice', approver: 'Historic Bob' } } }, { id: 'operator-2026', effectiveFrom: '2026-01-01', details: operator }]
describe('Verfahrensdokumentation and IKS (#9)', () => {
  it('validates required product sections, controls, evidence and exact component versions', () => { expect(validateProcedureVersion(procedure())).toEqual([]); expect(validateProcedureVersion({ ...procedure(), sections: { general: '' }, controls: {} })).toEqual(expect.arrayContaining(['Missing required section: general', 'Incomplete required control: separation-of-duties'])) })
  it('requires control evidence references to be arrays of nonblank IDs at runtime', () => { const stringEvidence = procedure(); stringEvidence.controls = { ...stringEvidence.controls, completeness: { description: 'Completeness', ownerRole: 'Controller', evidenceReferences: 'EV-1' as never } }; expect(validateProcedureVersion(stringEvidence)).toContain('Control has no evidence: completeness'); const blankEvidence = procedure(); blankEvidence.controls = { ...blankEvidence.controls, completeness: { description: 'Completeness', ownerRole: 'Controller', evidenceReferences: [' '] } }; expect(validateProcedureVersion(blankEvidence)).toContain('Control has no evidence: completeness') })
  it('requires every recorded procedure taxonomy version to be nonblank', () => { expect(validateProcedureVersion({ ...procedure(), taxonomyVersions: ['6.9', '  '] })).toContain('At least one nonblank taxonomy version is required.') })
  it('requires a stable document ID and at least one well-formed change-log entry', () => { expect(validateProcedureVersion({ ...procedure(), id: ' ', changeLog: [] })).toEqual(expect.arrayContaining(['Procedure document ID must be nonblank and stable.', 'At least one well-formed change-log entry with date, actor and summary is required.'])); expect(validateProcedureVersion({ ...procedure(), changeLog: [{ changedAt: '2026-02-30', changedBy: ' ', summary: ' ' }] })).toContain('At least one well-formed change-log entry with date, actor and summary is required.') })
  it('reports malformed runtime procedure documents and scalar metadata without throwing', () => {
    for (const malformed of [null, [], true, 'procedure']) {
      expect(() => validateProcedureVersion(malformed as never)).not.toThrow()
      expect(validateProcedureVersion(malformed as never)).toContain('Procedure document must be a structured object.')
    }
    for (const patch of [{ id: 17 }, { approvedBy: {} }, { version: null }, { appVersion: [] }, { configurationVersion: false }, { schemaVersion: {} }]) {
      const malformed = { ...procedure(), ...patch } as never
      expect(() => validateProcedureVersion(malformed)).not.toThrow()
      expect(validateProcedureVersion(malformed).length).toBeGreaterThan(0)
    }
  })
  it('creates a tenant-specific approved package and warns about incomplete operator controls', () => { const complete = createTenantProcedurePackage(procedure(), operator, '2026-06-01T00:00:00Z'); expect(complete.warnings).toEqual([]); const incomplete = createTenantProcedurePackage(procedure(), { ...operator, procedures: {} }, '2026-06-01T00:00:00Z'); expect(incomplete.warnings).toContain('Tenant procedure is incomplete: posting') })
  it('never marks a tenant package complete without assigned operators and indexed evidence', () => { const missing = createTenantProcedurePackage(procedure(), { ...operator, operatorRoles: {}, evidenceIndex: [] }, '2026-06-01T00:00:00Z'); expect(missing.warnings).toEqual(expect.arrayContaining(['Tenant operator roles require at least one nonblank role with an assigned operator.', 'Tenant evidence index requires at least one nonblank evidence reference.'])); expect(JSON.parse(missing.content).completeness.complete).toBe(false); const blank = createTenantProcedurePackage(procedure(), { ...operator, operatorRoles: { ' ': ' ', reviewer: '' }, evidenceIndex: [' '] }, '2026-06-01T00:00:00Z'); expect(JSON.parse(blank.content).completeness.complete).toBe(false) })
  it('does not count inherited tenant procedures or sparse evidence indexes as complete evidence', () => { const inheritedProcedures = Object.create(operator.procedures); const inherited = createTenantProcedurePackage(procedure(), { ...operator, procedures: inheritedProcedures }, '2026-06-01T00:00:00Z'); expect(inherited.warnings).toContain('Tenant procedure is incomplete: posting'); expect(JSON.parse(inherited.content).completeness.complete).toBe(false); const sparseEvidence = [...operator.evidenceIndex]; sparseEvidence.length += 1; const sparse = createTenantProcedurePackage(procedure(), { ...operator, evidenceIndex: sparseEvidence }, '2026-06-01T00:00:00Z'); expect(sparse.warnings).toContain('Tenant evidence index requires at least one nonblank evidence reference.'); expect(JSON.parse(sparse.content).completeness.complete).toBe(false) })
  it('cross-checks every required control evidence reference against the tenant evidence index', () => { const unrelated = createTenantProcedurePackage(procedure(), { ...operator, evidenceIndex: ['UNRELATED-EVIDENCE'] }, '2026-06-01T00:00:00Z'); expect(unrelated.warnings).toContain('Tenant evidence index is missing required control evidence: completeness'); expect(JSON.parse(unrelated.content).completeness.complete).toBe(false); expect(createTenantProcedurePackage(procedure(), operator, '2026-06-01T00:00:00Z').warnings).toEqual([]) })
  it('reproduces byte-identical historic packages from matching document and tenant-state snapshots', () => { const versions = [procedure('1.0.0', '2025-01-01', '2025-12-31T23:59:59Z'), procedure('2.0.0', '2026-01-01')]; const first = reproduceHistoricPackage(versions, operatorSnapshots, '2025-06-01T00:00:00Z'); const again = reproduceHistoricPackage(versions, operatorSnapshots, '2025-06-01T00:00:00Z'); expect(first).toEqual(again); expect(first.manifest).toMatchObject({ documentVersion: '1.0.0', tenantSnapshotId: 'operator-2025' }); expect(JSON.parse(first.content)).toMatchObject({ operator: { operatorRoles: { poster: 'Historic Alice' } }, operatorSnapshot: { id: 'operator-2025', effectiveFrom: '2025-01-01', effectiveTo: '2025-12-31' } }); expect(() => reproduceHistoricPackage(versions, operator as never, '2025-06-01T00:00:00Z')).toThrow('snapshots must be an array'); expect(() => reproduceHistoricPackage(versions, [{ ...operatorSnapshots[0], effectiveFrom: '2026-01-01', effectiveTo: '2026-12-31' }], '2025-06-01T00:00:00Z')).toThrow('effective at that date') })
  it('rejects invalid or reversed procedure effective boundaries and non-offset timestamps', () => { expect(validateProcedureVersion(procedure('1.0.0', '2026-02-30'))).toContain('Procedure effective boundaries are invalid or reversed.'); expect(validateProcedureVersion(procedure('1.0.0', '2026-02-01', '2026-01-01'))).toContain('Procedure effective boundaries are invalid or reversed.'); expect(validateProcedureVersion({ ...procedure(), approvedAt: '2026-01-01T10:00:00' })).toContain('Approval identity and real timestamp are required.') })
  it('requires a strict generation instant inside the effective interval and treats date-only end as inclusive', () => { const version = procedure('1.0.0', '2025-01-01', '2025-12-31'); expect(createTenantProcedurePackage(version, operator, '2025-12-31T23:00:00Z').manifest.documentVersion).toBe('1.0.0'); expect(() => createTenantProcedurePackage(version, operator, '2026-01-01T00:00:00Z')).toThrow('outside'); expect(() => createTenantProcedurePackage(version, operator, '2025-12-31T23:00:00')).toThrow('generation timestamp') })
  it('does not generate procedure evidence before the document approval instant', () => { expect(() => createTenantProcedurePackage({ ...procedure(), approvedAt: '2026-06-02T00:00:00Z' }, operator, '2026-06-01T00:00:00Z')).toThrow('predate document approval') })
  it('hard-fails invalid procedure boundaries before package interval comparisons', () => { expect(() => createTenantProcedurePackage({ ...procedure(), effectiveFrom: 'not-a-date' }, operator, '2026-06-01T00:00:00Z')).toThrow('effective boundaries'); expect(() => createTenantProcedurePackage({ ...procedure(), effectiveTo: 'not-a-date' }, operator, '2026-06-01T00:00:00Z')).toThrow('effective boundaries') })
})

