  it('reconciles commercial accounts to tax with permanent/temporary adjustments and applicable special/supplementary balances', () => { const report = createEBalanceReport({ ...eProfile, specialBalanceRequired: true, supplementaryBalanceRequired: true }, taxonomies[0], [{ concept: 'is.netIncome', context: 'duration', amountCents: 10000, unit: 'EUR', accountIds: ['net'] }], [{ id: 'perm', accountId: 'x', description: 'Non-deductible', type: 'PERMANENT', amountCents: 1000, evidenceIds: ['ev'] }, { id: 'temp', accountId: 'y', description: 'Timing', type: 'TEMPORARY', amountCents: -500, evidenceIds: ['ev2'] }], { ...emptyEAssets, specialBalance: supportingBalance('SPECIAL_BALANCE'), supplementaryBalance: supportingBalance('SUPPLEMENTARY_BALANCE') }, xbrlSerializer); expect(report.payload.taxReconciliation).toMatchObject({ permanentAdjustmentsCents: 1000, temporaryAdjustmentsCents: -500, taxNetIncomeCents: 10500 }); expect(() => createEBalanceReport({ ...eProfile, specialBalanceRequired: true }, taxonomies[0], [], [], emptyEAssets, xbrlSerializer)).toThrow('special balance') })
  it('rejects truthy or structurally incomplete required supporting-balance placeholders', () => { const profile = { ...eProfile, specialBalanceRequired: true }; const fact = [{ concept: 'is.netIncome', context: 'duration' as const, amountCents: 1, unit: 'EUR' as const, accountIds: [] }]; expect(() => createEBalanceReport(profile, taxonomies[0], fact, [], { ...emptyEAssets, specialBalance: {} as never }, xbrlSerializer)).toThrow('invalid identity or fiscal period'); const valid = supportingBalance('SPECIAL_BALANCE'); expect(() => createEBalanceReport(profile, taxonomies[0], fact, [], { ...emptyEAssets, specialBalance: { ...valid, facts: [] } }, xbrlSerializer)).toThrow('canonical facts'); expect(() => createEBalanceReport(profile, taxonomies[0], fact, [], { ...emptyEAssets, specialBalance: { ...valid, reconciliation: [{ ...valid.reconciliation[0], differenceCents: 2 }] } }, xbrlSerializer)).toThrow('invalid reconciliation data') })
