  it('requires tax-adjustment evidence to be an array of nonblank IDs', () => { const fact = [{ concept: 'is.netIncome', context: 'duration' as const, amountCents: 100, unit: 'EUR' as const, accountIds: [] }]; const adjustment = { id: 'adjustment', accountId: 'x', description: 'Adjustment', type: 'PERMANENT' as const, amountCents: 1, evidenceIds: ['e'] }; for (const evidenceIds of ['evidence' as never, [' ']]) expect(() => createEBalanceReport(eProfile, taxonomies[0], fact, [{ ...adjustment, evidenceIds }], emptyEAssets, xbrlSerializer)).toThrow('nonblank evidence IDs') })
  it('uses the unique duration net-income fact and never an instant fact', () => { const report = createEBalanceReport(eProfile, taxonomies[0], [{ concept: 'is.netIncome', context: 'instant', amountCents: 999, unit: 'EUR', accountIds: [] }, { concept: 'is.netIncome', context: 'duration', amountCents: 10, unit: 'EUR', accountIds: [] }], [], emptyEAssets, xbrlSerializer); expect(report.payload.taxReconciliation.commercialNetIncomeCents).toBe(10) })
  it('enforces fact account-ID arrays and exact nilReason semantics', () => { const base = { concept: 'is.netIncome', context: 'duration' as const, amountCents: 1, unit: 'EUR' as const, accountIds: [] }; for (const accountIds of ['8400' as never, [' ']]) expect(() => createEBalanceReport(eProfile, taxonomies[0], [{ ...base, accountIds }], [], emptyEAssets, xbrlSerializer)).toThrow('accountIds must be an array'); for (const nilReason of [undefined, '', ' ']) expect(() => createEBalanceReport(eProfile, taxonomies[0], [{ ...base, amountCents: null, nilReason }], [], emptyEAssets, xbrlSerializer)).toThrow('nilReason must be a nonblank string'); for (const nilReason of [undefined, 'notApplicable']) expect(() => createEBalanceReport(eProfile, taxonomies[0], [{ ...base, nilReason }], [], emptyEAssets, xbrlSerializer)).toThrow('absent for numeric facts') })
