    await expect(validateWithEric(report, { validate: vi.fn().mockResolvedValue({ valid: false, engineVersion: 'ERIC-45', diagnostics: [nonEnumerablePath] }) }, '2026-07-17T18:00:00Z')).rejects.toThrow('own enumerable data fields')
